class Solution {
    public boolean isFascinating(int n) {
        String s = String.valueOf(n);
        String s2 = String.valueOf(2 * n);
        String s3 = String.valueOf(3 * n);
        String combined = s + s2 + s3;
        char[] arr = combined.toCharArray();
        Arrays.sort(arr);
        return combined.equals(String.valueOf(arr));
    }
}
